mapper.update:
UPDATE t_trade_order
SET status = #{status}, update_time = NOW()
WHERE id = #{id}

UPDATE t_trade_order SET accumulated_income = accumulated_income + CASE id
WHEN #{item.id} THEN #{item.accumulatedIncome}
ELSE 0 END, update_time = NOW() WHERE id IN
#{item.id}

mapper.select:

SELECT o.* FROM t_trade_order o
WHERE o.status = 1
  AND o.id > #{lastId}
  AND MOD(o.user_id, #{shardTotal}) = #{shardIndex}
  AND NOT EXISTS (
    SELECT 1 FROM t_trade_daily_profit p
    WHERE p.order_id = o.id
      AND p.profit_date = #{bizDate}
)
ORDER BY o.id ASC
    LIMIT #{fetchSize}
